#include <vector>
#include <string>
using namespace std;

long long solve(long long n, vector<vector<long long>> edges, string label) {
    int nn = static_cast<int>(n);
    vector<vector<int>> adj(nn);
    for (auto &e : edges) {
        int u = static_cast<int>(e[0]);
        int v = static_cast<int>(e[1]);
        adj[u].push_back(v);
        adj[v].push_back(u);
    }

    int totalMasks = 1 << nn;
    vector<vector<int>> masks(nn + 1);
    for (int mask = 0; mask < totalMasks; mask++) {
        int cnt = __builtin_popcount(mask);
        if (cnt >= 1 && cnt <= nn) {
            masks[cnt].push_back(mask);
        }
    }

    vector<vector<vector<bool>>> dp(totalMasks, vector<vector<bool>>(nn, vector<bool>(nn, false)));
    for (int u = 0; u < nn; u++) {
        int mask = 1 << u;
        dp[mask][u][u] = true;
    }

    for (auto &e : edges) {
        int u = static_cast<int>(e[0]);
        int v = static_cast<int>(e[1]);
        if (label[u] == label[v]) {
            int mask = (1 << u) | (1 << v);
            dp[mask][u][v] = true;
            dp[mask][v][u] = true;
        }
    }

    int ans = 1;
    for (int cnt = 1; cnt <= nn; cnt++) {
        for (int mask : masks[cnt]) {
            for (int u = 0; u < nn; u++) {
                if (!(mask & (1 << u))) continue;
                for (int v = 0; v < nn; v++) {
                    if (!(mask & (1 << v))) continue;
                    if (!dp[mask][u][v]) continue;
                    if (cnt > ans) ans = cnt;
                    if (cnt + 2 > nn) continue;
                    for (int u2 : adj[u]) {
                        if (mask & (1 << u2)) continue;
                        for (int v2 : adj[v]) {
                            if (mask & (1 << v2)) continue;
                            if (u2 == v2) continue;
                            if (label[u2] != label[v2]) continue;
                            int new_mask = mask | (1 << u2) | (1 << v2);
                            if (dp[new_mask][u2][v2]) continue;
                            dp[new_mask][u2][v2] = true;
                            dp[new_mask][v2][u2] = true;
                        }
                    }
                }
            }
        }
    }
    return ans;
}
